const { useState, useMemo, useCallback, useEffect, useRef } = React;

/* ─────────────────────────────────────────────────────────────
   PERSISTENCE — localStorage-backed state.
   Mirrors useState's API so swapping is one-line: useState → usePersisted.
   Keyed under a versioned namespace so the schema can evolve cleanly.
   ───────────────────────────────────────────────────────────── */
const PERSIST_VERSION = "tapestry_v3";
const usePersisted = (key, defaultValue) => {
  const fullKey = `${PERSIST_VERSION}_${key}`;
  const [value, setValue] = React.useState(() => {
    try {
      const raw = window.localStorage?.getItem(fullKey);
      if (raw == null) return typeof defaultValue === "function" ? defaultValue() : defaultValue;
      return JSON.parse(raw);
    } catch { return typeof defaultValue === "function" ? defaultValue() : defaultValue; }
  });
  const skipRef = React.useRef(true);
  React.useEffect(() => {
    if (skipRef.current) { skipRef.current = false; return; }
    try { window.localStorage?.setItem(fullKey, JSON.stringify(value)); } catch {}
  }, [fullKey, value]);
  return [value, setValue];
};

const clearPersistedState = () => {
  try {
    Object.keys(window.localStorage || {}).filter(k => k.startsWith(PERSIST_VERSION)).forEach(k => window.localStorage.removeItem(k));
    window.location.reload();
  } catch {}
};

