/* buildStageMeta — a Proxy-wrapped meta map. Direct key access for ANY stage
   id always returns a usable object: real stages resolve normally, and a stage
   id not in the active pipeline (e.g. an in-flight study whose stage the team
   later removed) degrades to a neutral fallback instead of crashing on
   `.label` / `.color`. Object.keys / Object.entries still iterate real stages
   only, so funnels and pickers stay correct. */
const buildStageMeta = (arr) => {
  const base = Object.fromEntries(arr.map(s => [s.id, s]));
  return new Proxy(base, {
    get(t, k) {
      if (typeof k !== "string") return t[k];
      if (k in t) return t[k];
      /* Fallback for an orphaned stage id — title-case it, neutral color. */
      return { id:k, label: k.replace(/_/g, " ").replace(/\b\w/g, c => c.toUpperCase()),
               color:"#64748b", iconKey:"dot", targetDays:0, ownerTeamId:null, terminal:false, _fallback:true };
    },
  });
};

/* Live stage bindings — reassigned by applyPipelineStages() at boot. */
let PIPELINE_STAGES = DEFAULT_PIPELINE_STAGES;
let STAGES = PIPELINE_STAGES.map(s => s.id);
let STAGE_META = buildStageMeta(PIPELINE_STAGES);
let STAGE_TARGETS = Object.fromEntries(PIPELINE_STAGES.map(s => [s.id, s.targetDays]));
let STAGE_CUM_TARGETS = (() => {
  let cum = 0; const out = {};
  PIPELINE_STAGES.forEach(s => { cum += s.targetDays || 0; out[s.id] = cum; });
  return out;
})();
/* STAGE_TO_TEAM — derived from each stage's ownerTeamId. */
let STAGE_TO_TEAM = Object.fromEntries(PIPELINE_STAGES.map(s => [s.id, s.ownerTeamId]));

/* applyPipelineStages — swap in a team-defined pipeline. Idempotent; safe to
   call on every App render. Rebuilds all derived stage bindings. */
const applyPipelineStages = (stagesArr) => {
  if (!Array.isArray(stagesArr) || stagesArr.length === 0) return;
  PIPELINE_STAGES = stagesArr.map(s => ({ ...s }));
  STAGES = PIPELINE_STAGES.map(s => s.id);
  STAGE_META = buildStageMeta(PIPELINE_STAGES);
  STAGE_TARGETS = Object.fromEntries(PIPELINE_STAGES.map(s => [s.id, s.targetDays]));
  let cum = 0; const cumOut = {};
  PIPELINE_STAGES.forEach(s => { cum += s.targetDays || 0; cumOut[s.id] = cum; });
  STAGE_CUM_TARGETS = cumOut;
  STAGE_TO_TEAM = Object.fromEntries(PIPELINE_STAGES.map(s => [s.id, s.ownerTeamId]));
};

/* Compute days until / past the current stage's target. Negative = overdue.
   Returns null if study hasn't been committed (no anchor date). */
const computeStageCountdown = (study, stageKey) => {
  if (!study || !stageKey) return null;
  const anchor = study.committedAt || study.intakeDate;
  if (!anchor) return null;
  const today0 = new Date(); today0.setHours(0,0,0,0);
  const anchorDate = new Date(anchor);
  const elapsed = Math.floor((today0 - anchorDate) / 86400000);
  const target = STAGE_CUM_TARGETS[stageKey] || 0;
  const daysLeft = target - elapsed;
  return {
    daysLeft,                                       /* positive = days to go; negative = overdue */
    elapsed,
    target,
    status: daysLeft < -7 ? "overdue" : daysLeft < 0 ? "late" : daysLeft <= 7 ? "due-soon" : "on-track",
  };
};

/* Render-helper: small chip showing the countdown for one stage. */
const stageCountdownLabel = (cd) => {
  if (!cd) return null;
  if (cd.daysLeft >= 0) return `${cd.daysLeft}d left`;
  return `-${Math.abs(cd.daysLeft)}d`;
};

/* Activation is terminal — no meaningful countdown. Caller should suppress
   the chip for these stages. */
const STAGE_HAS_COUNTDOWN = (stageKey) => stageKey && stageKey !== "activation";

