/* ─────────────────────────────────────────────────────────────
   UTILITIES
   ───────────────────────────────────────────────────────────── */
let _uid = 1000;
const uid = (p="id") => `${p}_${++_uid}`;
const fmtDate = d => d ? new Date(d).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}) : "—";
const fmtMoney = n => new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",maximumFractionDigits:0}).format(n||0);

/* Group items (each with a `.study` attached) by study, sorted by recency.
   The shape items use: { ..., study: { id, code, title, ta } }
   Returns: [{ studyCode, study, items }] in the same order items first appeared. */
const groupByStudyKey = (items) => {
  const order = [];
  const buckets = {};
  (items || []).forEach(it => {
    const s = it.study;
    if (!s) return;
    if (!buckets[s.code]) {
      buckets[s.code] = { studyCode: s.code, study: s, items: [] };
      order.push(s.code);
    }
    buckets[s.code].items.push(it);
  });
  return order.map(k => buckets[k]);
};
const daysAgo = n => { const d=new Date(); d.setDate(d.getDate()-n); return d.toISOString().slice(0,10); };
const daysFromNow = n => { const d=new Date(); d.setDate(d.getDate()+n); return d.toISOString().slice(0,10); };
/* todayCtx — single helper for the date-stamp pattern. Returns { iso, human, short }
   so any handler can grab consistent strings for state, toasts, and audit details. */
const todayCtx = () => {
  const d = new Date();
  return {
    iso:   d.toISOString().slice(0,10),
    human: d.toLocaleDateString("en-US", { weekday:"short", month:"short", day:"numeric", year:"numeric" }),
    short: d.toLocaleDateString("en-US", { month:"short", day:"numeric", year:"numeric" }),
  };
};
const stageIdx = s => Math.max(0, STAGES.indexOf(s));
const pct = (a,b) => b ? Math.round((a/b)*100) : 0;

/* ─────────────────────────────────────────────────────────────
   SP0-001 PROJECT HEALTH — single rolled-up R/Y/G signal per study.
   Mirrors the spreadsheet world coordinators come from: one
   color tells you whether to look.

   Inputs (all optional — health degrades gracefully if missing):
   - open escalations + severity
   - overdue tasks count + worst-overdue days
   - estimatedActivationDate vs today (if set)
   - workflow execution: overdue ready tasks

   Returns: { level: "red"|"yellow"|"green", reason, daysOverdue? }
   ───────────────────────────────────────────────────────────── */
const PROJECT_HEALTH_META = {
  red:    { label:"Red",    color:"#dc2626", bg:"#fee2e2", iconKey:"alert" },
  yellow: { label:"Yellow", color:"#b45309", bg:"#fef3c7", iconKey:"alert" },
  green:  { label:"Green",  color:"#059669", bg:"#d1fae5", iconKey:"check" },
};

const computeProjectHealth = (study) => {
  if (!study) return { level:"green", reason:"No study", daysOverdue:0 };
  const today0 = new Date(); today0.setHours(0,0,0,0);

  /* 1. Open escalations weigh heaviest. */
  const openEsc = (study.escalations || []).filter(e => !e.resolvedDate);
  const criticalEsc = openEsc.filter(e => e.severity === "critical");
  if (criticalEsc.length > 0) return { level:"red", reason:`${criticalEsc.length} critical escalation${criticalEsc.length === 1 ? "" : "s"} open`, daysOverdue:0 };

  /* 2. Overdue tasks. Pick the worst-overdue. */
  const overdueTasks = (study.tasks || [])
    .filter(t => t.status !== "completed" && t.due)
    .map(t => ({ t, days: Math.floor((today0 - new Date(t.due)) / 86400000) }))
    .filter(x => x.days > 0);
  const worstOverdue = overdueTasks.reduce((m, x) => Math.max(m, x.days), 0);

  if (worstOverdue > 30) return { level:"red", reason:`Task overdue ${worstOverdue} day${worstOverdue === 1 ? "" : "s"}`, daysOverdue:worstOverdue };

  /* 3. Activation date in the past. */
  if (study.details?.estimatedActivationDate) {
    const eaDate = new Date(study.details.estimatedActivationDate);
    const daysPastActivation = Math.floor((today0 - eaDate) / 86400000);
    if (daysPastActivation > 30 && !study.details.activationDate) {
      return { level:"red", reason:`Activation ${daysPastActivation} days overdue`, daysOverdue:daysPastActivation };
    }
    if (daysPastActivation > 0 && !study.details.activationDate) {
      return { level:"yellow", reason:`Activation ${daysPastActivation} days overdue`, daysOverdue:daysPastActivation };
    }
  }

  /* 4. High-severity escalation OR moderate overdue → yellow. */
  const highEsc = openEsc.filter(e => e.severity === "high");
  if (highEsc.length > 0) return { level:"yellow", reason:`${highEsc.length} high-severity escalation${highEsc.length === 1 ? "" : "s"}`, daysOverdue:0 };
  if (worstOverdue > 0) return { level:"yellow", reason:`Task overdue ${worstOverdue} day${worstOverdue === 1 ? "" : "s"}`, daysOverdue:worstOverdue };
  if (openEsc.length > 0) return { level:"yellow", reason:`${openEsc.length} open escalation${openEsc.length === 1 ? "" : "s"}`, daysOverdue:0 };

  /* 5. Clean. */
  return { level:"green", reason:"On track", daysOverdue:0 };
};

/* SPONSOR PULSE — 5-segment thermometer indicating sponsor-relationship freshness.
   Reads study.budget.lastContact (the most recent sponsor touchpoint).
   Returns { segments: 1..5, color, label, days, sub }. Renders compactly via the
   <SponsorPulse> primitive below. */
const computeSponsorPulse = (study) => {
  if (!study) return null;
  const today0 = new Date(); today0.setHours(0,0,0,0);
  const lastContact = study.budget?.lastContact;
  if (!lastContact) {
    return { segments:0, color:"#94a3b8", label:"No contact data", days:null, sub:"—" };
  }
  const days = Math.floor((today0 - new Date(lastContact)) / 86400000);
  if (days <= 7)   return { segments:5, color:"#10b981", label:"Active",    days, sub:`Last contact ${days}d ago` };
  if (days <= 14)  return { segments:4, color:"#10b981", label:"Engaged",   days, sub:`Last contact ${days}d ago` };
  if (days <= 30)  return { segments:3, color:"#f59e0b", label:"Slowing",   days, sub:`Last contact ${days}d ago` };
  if (days <= 60)  return { segments:2, color:"#f59e0b", label:"Quiet",     days, sub:`Last contact ${days}d ago` };
  return             { segments:1, color:"#ef4444", label:"Silent",     days, sub:`Last contact ${days}d ago — likely needs a nudge` };
};

/* Compact 5-segment pulse meter. Renders inline. */
const SponsorPulse = ({ pulse, compact = false }) => {
  if (!pulse) return null;
  const segments = 5;
  return (
    <span title={`Sponsor pulse: ${pulse.label} — ${pulse.sub}`} style={{ display:"inline-flex", alignItems:"center", gap:5, whiteSpace:"nowrap" }}>
      <span style={{ display:"inline-flex", gap:2 }}>
        {Array.from({ length: segments }).map((_, i) => (
          <span key={i} style={{
            width: compact ? 4 : 5,
            height: compact ? 10 : 12,
            borderRadius:1.5,
            background: i < pulse.segments ? pulse.color : "#e2e8f0",
            transition:"background .12s",
          }} />
        ))}
      </span>
      {!compact && (
        <span style={{ fontSize:10, color:pulse.color, fontWeight:600, textTransform:"uppercase", letterSpacing:"0.06em" }}>{pulse.label}</span>
      )}
    </span>
  );
};

/* CUSTODY — who currently holds the next action on a study. Answers the
   "where is the ball" question. Returns { label, sub, external, color, days }.
   external = the ball is outside the site's walls (sponsor / CRO).
   Computed from budget negotiation state when active, else from the team that
   owns the study's current pipeline stage. */
const computeCustody = (study, teams) => {
  if (!study) return null;
  const today0 = new Date(); today0.setHours(0,0,0,0);
  const daysSince = (d) => d ? Math.floor((today0 - new Date(d)) / 86400000) : null;

  if (study.closed) return { label:"Closed", sub:"Study closed out", external:false, color:"#64748b", days:null };
  if (study.stage === "activation") return { label:"Your team", sub:"Activated — internal", external:false, color:"#059669", days:null };

  /* Budget negotiation is the clearest custody signal when it's live. */
  const b = study.budget;
  if (b && b.status === "negotiating") {
    if (b.handoff === "sponsor") {
      const d = b.daysWithSponsor || daysSince(b.lastContact);
      return { label:"Sponsor / CRO", sub:"Budget with sponsor", external:true, color:"#b45309", days:d };
    }
    if (b.handoff === "site") {
      const d = b.daysWithSite || daysSince(b.lastContact);
      return { label:"Budget & Contracts", sub:"Budget under internal review", external:false, color:"#BE185D", days:d };
    }
  }

  /* Otherwise the team that owns the current stage holds it. */
  const tid = STAGE_TO_TEAM[study.stage];
  const team = (teams || []).find(t => t.id === tid);
  const cd = computeStageCountdown(study, study.stage);
  return {
    label: team?.name || "Your team",
    sub: `In ${STAGE_META[study.stage]?.label || study.stage}`,
    external: false,
    color: team?.color || "#4F46E5",
    days: cd?.elapsed ?? null,
  };
};

/* Compact custody chip. external custody renders with an outbound arrow. */
const CustodyChip = ({ custody, compact = false }) => {
  if (!custody) return null;
  return (
    <span title={`Custody: ${custody.label}${custody.days != null ? ` · ${custody.days}d` : ""} — ${custody.sub}`}
      style={{
        display:"inline-flex", alignItems:"center", gap:4, whiteSpace:"nowrap",
        padding: compact ? "1px 7px" : "2px 9px", borderRadius:999,
        background:`${custody.color}14`, border:`1px solid ${custody.color}33`,
        fontSize: compact ? 10 : 11, fontWeight:600, color:custody.color,
      }}>
      <Icon name={custody.external ? "send" : "users"} size={compact ? 8 : 9} color={custody.color} />
      {custody.label}{custody.days != null ? ` · ${custody.days}d` : ""}
    </span>
  );
};

