/* For Today/Calendar: synthesize a few upcoming events from study state. */
const upcomingEvents = (studies) => {
  const evs = [];
  studies.forEach(s => {
    if (s.siv?.scheduled) evs.push({ id:`siv-${s.id}`, date:s.siv.scheduled, kind:"SIV", studyCode:s.code, title:`Site Initiation Visit · ${s.code}`, color:"#06b6d4" });
    if (s.cta?.dueDate) evs.push({ id:`cta-${s.id}`, date:s.cta.dueDate, kind:"CTA", studyCode:s.code, title:`CTA response due · ${s.code}`, color:"#8b5cf6" });
    (s.tasks||[]).filter(t => t.status !== "completed").forEach(t => {
      evs.push({ id:`tk-${t.id}`, date:t.due, kind:"Task", studyCode:s.code, title:t.title, color:"#f59e0b", priority:t.priority });
    });
  });
  return evs.sort((a,b) => new Date(a.date) - new Date(b.date));
};

