/* Helpers — convenient lookups */
const documentTypeById = (id) => DOCUMENT_TYPES[id] || null;
const documentTypesArr = Object.values(DOCUMENT_TYPES);
const documentTypesForArtifact = (taxonomy, artifactCode) => documentTypesArr.filter(t => taxonomy === "isf" ? t.isfArtifactId === artifactCode : t.tmfArtifactId === artifactCode);

/* Slugify a value for use inside a filename (no spaces, no slashes). */
const slug = (s) => String(s || "").replace(/[^A-Za-z0-9_-]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 60);

/* Format a document name from a Document Type's naming template + attribute values.
   The values map can hold raw values or data-source entry IDs — for the latter we
   look up the entry's `value` from the live dataSources state. */
const formatDocumentName = (docType, attrs, dataSources, peopleById) => {
  if (!docType) return "Document.pdf";
  const allAttrs = [...(docType.requiredAttributes || []), ...(docType.optionalAttributes || [])];
  let out = docType.namingTemplate || `${docType.name.replace(/\s+/g, "")}_{date}`;
  allAttrs.forEach(spec => {
    const raw = attrs ? attrs[spec.key] : undefined;
    let display = "";
    if (raw == null || raw === "") display = "";
    else if (spec.type === "data-source" && dataSources) {
      const ds = dataSources[spec.dataSourceId];
      const entry = ds && ds.entries.find(e => e.id === raw);
      display = entry ? entry.value : String(raw);
    } else if (spec.type === "person" && peopleById) {
      const p = peopleById[raw];
      display = p ? p.name : String(raw);
    } else {
      display = String(raw);
    }
    out = out.replace(`{${spec.key}}`, slug(display));
  });
  /* Clean up double underscores left by empty optional fields */
  out = out.replace(/_{2,}/g, "_").replace(/^_+|_+$/g, "");
  return `${out}.pdf`;
};

/* Resolve the TMF/ISF zone code (e.g. "05") a Document Type should file under. */
const zoneForDocType = (docType, taxonomy = "tmf") => {
  if (!docType) return null;
  if (taxonomy === "isf") {
    const code = docType.isfArtifactId;
    if (!code) return null;
    const z = code.split(".")[0]; /* "ISF_07" */
    return z.replace("ISF_", ""); /* "07" */
  }
  const code = docType.tmfArtifactId;
  return code ? code.split(".")[0] : null;
};

/* ─────────────────────────────────────────────────────────────
   CENTRAL BINDER (Phase 3) — cross-study shared document library.
   Stores documents that aren't study-specific (CVs, training certs,
   FWAs, IRB rosters, CLIA/CAP, IBs, package inserts) once. Each
   study's "binder setup" selects entities (PIs, IRBs, labs, drugs,
   etc.) — the pull engine then surfaces matching central documents
   into that study's binder, with Trial Start Date as the temporal
   cutoff for "current as of" versioning.

   This is the Complion moat. CRCs don't re-upload the same PI CV to
   five studies; they upload once and pick the PI on each study.
   ───────────────────────────────────────────────────────────── */
