/* Build the universe of owner-entity options for a given kind.
   Pulls from data sources where wired, plus from current studies'
   personnel (for "person" kind, which has no dedicated data source). */
const centralOwnerOptions = (kind, dataSources, studies) => {
  const meta = centralOwnerKindMeta(kind);
  if (!meta) return [];
  if (meta.dataSourceId) {
    return ((dataSources[meta.dataSourceId]?.entries) || []).filter(e => !e.deprecated).map(e => ({ id:e.id, name:e.value }));
  }
  if (kind === "person") {
    const set = new Map();
    (studies || []).forEach(s => {
      if (s.pi) set.set(s.pi, { name: s.pi, role: "PI" });
      (s.personnel || []).forEach(p => set.set(p.name, { name: p.name, role: p.role }));
    });
    return Array.from(set.values()).sort((a,b) => a.name.localeCompare(b.name)).map(p => ({ id: p.name, name: p.name, role: p.role }));
  }
  /* policy / template — free-form */
  return [{ id: kind === "policy" ? "Site SOPs" : "NTF Templates", name: kind === "policy" ? "Site SOPs" : "NTF Templates" }];
};

/* Pull engine — given a study (with binderSetup) and the central
   library, returns the list of central documents that flow into
   the study's binder. Pure function. */
const pullCentralForStudy = (study, centralDocs) => {
  if (!study || !centralDocs) return [];
  const setup = study.binderSetup || {};
  const cutoff = setup.trialStartDate || study.intakeDate || new Date().toISOString().slice(0,10);
  const inRange = (doc) => {
    /* Must be effective on or before the cutoff (or no cutoff yet) */
    if (cutoff && doc.effectiveDate && doc.effectiveDate > cutoff) return false;
    /* If expired before cutoff, still file as historical-eligible — but flag */
    return true;
  };
  const matchesSelection = (doc) => {
    const k = doc.ownerKind;
    if (k === "person")   return (setup.personNames   || []).includes(doc.ownerName);
    if (k === "sponsor")  return (setup.sponsorNames  || []).includes(doc.ownerName);
    if (k === "irb")      return (setup.irbNames      || []).includes(doc.ownerName);
    if (k === "lab")      return (setup.labNames      || []).includes(doc.ownerName);
    if (k === "drug")     return (setup.drugNames     || []).includes(doc.ownerName);
    if (k === "device")   return (setup.deviceNames   || []).includes(doc.ownerName);
    if (k === "policy")   return !!setup.pullPolicies;     /* opt-in */
    if (k === "template") return !!setup.pullTemplates;    /* opt-in */
    return false;
  };

  return centralDocs
    .filter(d => d.status !== "superseded" && d.status !== "deprecated")
    .filter(matchesSelection)
    .filter(inRange)
    .map(d => {
      /* Mark expiring/expired based on expirationDate vs today (not cutoff). */
      let expiryFlag = null;
      if (d.expirationDate) {
        const today0 = new Date(); today0.setHours(0,0,0,0);
        const exp = new Date(d.expirationDate);
        const days = Math.round((exp - today0) / 86400000);
        if (days < 0) expiryFlag = "expired";
        else if (days <= 30) expiryFlag = "expiring";
      }
      return { ...d, _pulled:true, _expiryFlag: expiryFlag };
    });
};

/* ─────────────────────────────────────────────────────────────
   EMAIL-INTO-BINDER (Phase 4)
   Per-study forwarding address. Deterministically derived from
   study code + ID hash so it's stable across reloads. In the
   demo we simulate inbound mail; real implementation needs a
   backend inbound mail handler.
   ───────────────────────────────────────────────────────────── */
const studyForwardingEmail = (study) => {
  if (!study) return "";
  const slug = (study.code || "").toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
  const idHash = (study.id || "").split("").reduce((a, c, i) => ((a * 31 + c.charCodeAt(0)) | 0), 7);
  const suffix = ((idHash >>> 0) % 0x10000000).toString(16).padStart(7, "0").slice(0, 7);
  return `binder-${slug || "study"}-${suffix}@in.platypus.io`;
};

