/* Compute live status from end date — if past, mark as expired. */
const computeExternalUserStatus = (eu) => {
  if (eu.status === "revoked") return "revoked";
  const today0 = new Date().toISOString().slice(0,10);
  if (eu.endDate && eu.endDate < today0) return "expired";
  return "active";
};

const externalUsersForStudy = (externalUsers, studyId) => (externalUsers || []).filter(eu => (eu.scopedStudyIds || []).includes(studyId) && computeExternalUserStatus(eu) === "active");

