/* Coverage — for a study + package, which artifacts are filed, expiring, missing. */
const submissionPackageCoverage = (study, _ignored, packageId) => {
  const pkg = SUBMISSION_PACKAGES[packageId];
  if (!pkg) return null;
  const ownDocs = (study?.documents || []).filter(d => d.status !== "removed" && d.status !== "unfiled");
  const artifacts = pkg.artifacts.map(code => {
    const artMeta = tmfArtifactByCode(code);
    const own  = ownDocs.find(d => d.tmfArtifactId === code || d.artifactCode === code);
    let status = "missing";
    if (own) status = own.status === "current" || own.status === "approved" ? "filed" : "pending";
    return { code, name: artMeta?.name || code, required: !!artMeta?.required, source: own ? "study" : null, status, doc: own };
  });
  const filed   = artifacts.filter(a => a.status === "filed" || a.status === "expiring").length;
  const missing = artifacts.filter(a => a.status === "missing").length;
  const expiring= artifacts.filter(a => a.status === "expiring").length;
  const expired = artifacts.filter(a => a.status === "expired").length;
  const completePct = artifacts.length ? Math.round((filed / artifacts.length) * 100) : 0;
  return { pkg, artifacts, filed, missing, expiring, expired, completePct };
};

/* ─────────────────────────────────────────────────────────────
   CROSS-BINDER ACTIVITY FEED (Phase 5)
   Aggregates portfolio-wide events worth surfacing on Today.
   ───────────────────────────────────────────────────────────── */
const crossBinderActivity = (studies, centralDocs) => {
  const items = [];
  const today0 = new Date(); today0.setHours(0,0,0,0);

  /* Central docs expiring/expired that affect ≥1 study */
  (centralDocs || []).forEach(d => {
    if (!d.expirationDate || d.status === "deprecated" || d.status === "superseded") return;
    const days = Math.round((new Date(d.expirationDate) - today0) / 86400000);
    if (days > 60) return;
    const affectedStudies = (studies || []).filter(s => pullCentralForStudy(s, centralDocs).some(p => p.id === d.id));
    if (affectedStudies.length === 0) return;
    items.push({
      id: `cd-exp-${d.id}`,
      severity: days < 0 ? "critical" : days <= 14 ? "warning" : "info",
      iconKey: days < 0 ? "alert" : "alert",
      title: days < 0 ? `${d.name} — expired ${Math.abs(days)}d ago` : days === 0 ? `${d.name} — expires today` : `${d.name} — expires in ${days}d`,
      sub: `Affects ${affectedStudies.map(s => s.code).join(", ")}`,
      date: d.expirationDate,
      kind: "expiry",
    });
  });

  /* Central docs recently superseded — flag studies that may need to refresh references */
  (centralDocs || []).forEach(d => {
    if (d.status !== "current" || !d.supersedesId) return;
    const days = Math.round((today0 - new Date(d.uploadedAt)) / 86400000);
    if (days > 30) return;
    const affectedStudies = (studies || []).filter(s => pullCentralForStudy(s, centralDocs).some(p => p.id === d.id));
    if (affectedStudies.length === 0) return;
    items.push({
      id: `cd-sup-${d.id}`,
      severity: "info",
      iconKey: "history",
      title: `${d.name} — superseded prior version`,
      sub: `Affects ${affectedStudies.map(s => s.code).join(", ")} · ${days}d ago`,
      date: d.uploadedAt,
      kind: "supersede",
    });
  });

  /* Late filings across the portfolio */
  let lateCount = 0;
  (studies || []).forEach(s => {
    const recent = (s.documents || []).filter(d => d.uploaded && !d.filedAt && d.status !== "removed");
    lateCount += recent.length;
  });
  /* (no specific late-filing data — skipped) */

  /* Unfiled docs accumulating */
  const unfiledByStudy = (studies || []).map(s => ({ s, n: (s.documents || []).filter(d => d.status === "unfiled" || !d.documentTypeId).length })).filter(x => x.n >= 2);
  unfiledByStudy.forEach(x => items.push({
    id: `unfiled-${x.s.id}`,
    severity: "info",
    iconKey: "alert",
    title: `${x.s.code} has ${x.n} unfiled documents`,
    sub: "Classify them so they file to the right binder zone.",
    date: new Date().toISOString().slice(0,10),
    kind: "unfiled",
    studyId: x.s.id,
  }));

  return items.sort((a,b) => {
    const order = { critical:0, warning:1, info:2 };
    if (order[a.severity] !== order[b.severity]) return order[a.severity] - order[b.severity];
    return new Date(a.date) - new Date(b.date);
  });
};

/* Coverage summary for a study — how many central docs pulled, how many study-specific, how many required artifacts still missing. */
const studyBinderCoverage = (study, centralDocs) => {
  const pulled = pullCentralForStudy(study, centralDocs);
  const studyOwn = (study?.documents || []).filter(d => d.status !== "unfiled");
  const unfiled = (study?.documents || []).filter(d => d.status === "unfiled" || !d.documentTypeId).length;
  return {
    pulledCount:   pulled.length,
    studyOwnCount: studyOwn.length,
    unfiledCount:  unfiled,
    expiringFromCentral: pulled.filter(p => p._expiryFlag === "expiring").length,
    expiredFromCentral:  pulled.filter(p => p._expiryFlag === "expired").length,
  };
};

/* Compute TMF/ISF status for a single study. Accepts a taxonomy parameter
   ("tmf" or "isf") and computes against the appropriate reference model.
   Returns { artifacts: [{ ...artifact, status, doc, daysLate }],
             summary: { complete, missing, expiring, expired, total,
                        completePct, timelyPct, qualityPct, healthScore },
             taxonomy }
   Status values: "filed_current", "filed_late", "missing", "expiring",
                  "expired", "not_applicable" */
const computeTmfStatus = (study, taxonomy = "tmf") => {
  if (!study) return { artifacts: [], summary: { complete:0, missing:0, expiring:0, expired:0, total:0, completePct:0, timelyPct:0, qualityPct:0, healthScore:0 }, taxonomy };
  const today = new Date();
  const refSet = taxonomy === "isf" ? ISF_ALL_ARTIFACTS : TMF_ALL_ARTIFACTS;
  const artifacts = refSet.map((art, idx) => {
    /* Match a present document via category or name token. We hash the
       study id + artifact code to deterministically decide which artifacts
       are filed in this demo. */
    const seed = (study.id + art.code).split("").reduce((a, c) => a + c.charCodeAt(0), 0);
    const isFiled = (seed % 10) > 2; // ~70% filed
    const isLate = isFiled && (seed % 17) === 0; // ~6% filed late
    const isExpired = isFiled && (seed % 23) === 0; // ~4% expired
    const isExpiring = isFiled && !isExpired && (seed % 29) === 0;
    let status;
    if (!isFiled) status = "missing";
    else if (isExpired) status = "expired";
    else if (isExpiring) status = "expiring";
    else if (isLate) status = "filed_late";
    else status = "filed_current";
    return { ...art, status, idx, daysLate: isLate ? (seed % 14) + 1 : 0, expiresIn: isExpiring ? 14 - (seed % 14) : null };
  });

  const total = artifacts.filter(a => a.required).length;
  const present = artifacts.filter(a => a.required && (a.status === "filed_current" || a.status === "filed_late" || a.status === "expiring")).length;
  const missing = artifacts.filter(a => a.required && a.status === "missing").length;
  const expiring = artifacts.filter(a => a.required && a.status === "expiring").length;
  const expired = artifacts.filter(a => a.required && a.status === "expired").length;
  const filedTimely = artifacts.filter(a => a.required && a.status === "filed_current").length;
  const filedTotal = artifacts.filter(a => a.required && (a.status === "filed_current" || a.status === "filed_late")).length;

  const completePct = total ? Math.round((present / total) * 100) : 0;
  const timelyPct = filedTotal ? Math.round((filedTimely / filedTotal) * 100) : 0;
  /* Quality score is a stable, study-specific number */
  const seed = study.id.split("").reduce((a, c) => a + c.charCodeAt(0), 0);
  const qualityPct = 70 + (seed % 28);
  const healthScore = Math.round((completePct * 0.5) + (timelyPct * 0.3) + (qualityPct * 0.2));

  return { artifacts, summary: { complete: present, missing, expiring, expired, total, completePct, timelyPct, qualityPct, healthScore }, taxonomy };
};

