/* Deep-copy a template into a fresh workflow object with new IDs.
   Used by the onboarding wizard to instantiate a template per study type. */
/* instantiateTemplate — clone a workflow template for a specific study type.
   overrides (optional) — wizard Stage 4 inline customizations:
     { name: "Workflow name override",
       modules: { [origModuleId]: { name?, team? } },
       tasks:   { [origTaskId]:   { label? } } }
   When overrides aren't provided, behaves as the original implementation. */
const instantiateTemplate = (template, studyTypeLabel, overrides) => {
  const idMap = {};
  const mod_o = (overrides && overrides.modules) || {};
  const tsk_o = (overrides && overrides.tasks)   || {};
  const wf = {
    id: uid("wf"),
    name: (overrides && overrides.name && overrides.name.trim())
      || (studyTypeLabel ? `${studyTypeLabel} (from ${template.name})` : template.name),
    state: "draft",
    createdAt: new Date().toISOString().slice(0,10),
    publishedAt: null,
    description: template.description,
    fromTemplate: template.id,
    modules: (template.modules || []).map(m => {
      const newModId = uid("mod");
      idMap[m.id] = newModId;
      const mo = mod_o[m.id] || {};
      return {
        ...m,
        id: newModId,
        name: (mo.name && mo.name.trim()) || m.name,
        team: mo.team || m.team,
        tasks: (m.tasks || []).map(t => {
          const newTaskId = uid("tk");
          idMap[t.id] = newTaskId;
          const to = tsk_o[t.id] || {};
          return { ...t, id: newTaskId, label: (to.label && to.label.trim()) || t.label };
        }),
      };
    }),
  };
  /* Remap handoff targets to the new IDs */
  wf.modules = wf.modules.map(m => ({
    ...m,
    tasks: m.tasks.map(t => t.target?.moduleId
      ? { ...t, target: { moduleId: idMap[t.target.moduleId] || null, taskId: idMap[t.target.taskId] || null } }
      : t),
  }));
  return wf;
};

