/* Notifications. The bell in the header surfaces unread items here.
   Each notification clicks through to the relevant study or page. */
const minutesAgo = (m) => { const d = new Date(); d.setMinutes(d.getMinutes() - m); return d.toISOString(); };
const hoursAgo   = (h) => { const d = new Date(); d.setHours(d.getHours() - h); return d.toISOString(); };
const fmtRelTime = (iso) => {
  if (!iso) return "—";
  const diffMs = new Date() - new Date(iso);
  const m = Math.round(diffMs / 60000);
  if (m < 1) return "just now";
  if (m < 60) return `${m}m ago`;
  const h = Math.round(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.round(h / 24);
  if (d < 7) return `${d}d ago`;
  return fmtDate(iso);
};

