const Icon = ({ name, size = 16, color = "currentColor", strokeWidth = 2, style }) => {
  const d = ICON_PATHS[name] || ICON_PATHS.dot;
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none"
      stroke={color} strokeWidth={strokeWidth} strokeLinecap="round" strokeLinejoin="round"
      style={{ flexShrink: 0, display: "block", ...style }}>
      <path d={d} />
    </svg>
  );
};

/* ─────────────────────────────────────────────────────────────
   PRIMITIVES
   ───────────────────────────────────────────────────────────── */
const Btn = ({ children, variant="default", size="md", onClick, style, disabled, type="button" }) => {
  /* Pill radius is the brand default. Primary is the brand gradient.
     Secondary is white with a 1px border. Ghost-on-brand is for the
     gradient header. */
  const sizes = { sm:"6px 12px", md:"9px 18px", lg:"11px 22px" };
  const fontSizes = { sm:T.font.sm, md:T.font.base, lg:T.font.base };
  const [h, setH] = useState(false);

  const styles = {
    primary: {
      background: T.color.brandGradient,
      color:"#fff", border:"none",
      boxShadow: h ? T.shadow.brandHover : T.shadow.brand,
    },
    success: {
      background: T.color.success,
      color:"#fff", border:"none",
      boxShadow: h ? "0 4px 14px rgba(5,150,105,.35)" : "0 2px 8px rgba(5,150,105,.25)",
    },
    danger: {
      background: h ? "#fee2e2" : T.color.dangerBg,
      color: T.color.danger, border:`1px solid ${T.color.dangerBorder}`,
    },
    ghost: {
      background: h ? T.color.surfaceAlt : "transparent",
      color: T.color.textSecondary, border:`1px solid ${T.color.border}`,
    },
    quiet: {
      background: h ? T.color.surfaceAlt : "transparent",
      color: T.color.textSecondary, border:"none",
    },
    "ghost-brand": {
      background: h ? "rgba(255,255,255,.22)" : "rgba(255,255,255,.14)",
      color:"#fff", border:"1px solid rgba(255,255,255,.22)",
      backdropFilter:"saturate(180%) blur(8px)",
    },
    default: {
      background: h ? T.color.surfaceAlt : T.color.surface,
      color: T.color.text, border:`1px solid ${T.color.border}`,
    },
  };
  const v = styles[variant] || styles.default;

  return (
    <button type={type} onClick={onClick} disabled={disabled}
      onMouseEnter={()=>setH(true)} onMouseLeave={()=>setH(false)}
      style={{
        padding:sizes[size], borderRadius:T.radius.pill,
        ...v,
        ...(disabled ? { background:T.color.surfaceAlt, color:T.color.textFaint, boxShadow:"none" } : {}),
        fontFamily:T.font.sans, fontSize:fontSizes[size], fontWeight:T.weight.semi,
        cursor: disabled ? "not-allowed" : "pointer",
        transition:"all .15s cubic-bezier(.32,.72,0,1)",
        display:"inline-flex", alignItems:"center", gap:6,
        whiteSpace:"nowrap", lineHeight:1.4,
        ...style,
      }}>{children}</button>
  );
};

/* Pill — 999px radius is the brand default. Tabular nums for any number content. */
const Pill = ({ children, color=T.color.textSecondary, bg, border, size="sm" }) => (
  <span style={{
    display:"inline-flex", alignItems:"center", gap:5,
    padding: size==="sm" ? "2px 9px" : "3px 11px",
    borderRadius:T.radius.pill, background: bg || `${color}14`,
    color, fontFamily:T.font.sans, fontSize: size==="sm" ? T.font.xs : T.font.sm,
    fontWeight:T.weight.semi, letterSpacing:"0.2px",
    lineHeight:1.4, whiteSpace:"nowrap",
    fontVariantNumeric:"tabular-nums",
    border: border || "none",
  }}>{children}</span>
);

/* m4 (USABILITY_REVIEW) — role-task plumbing. Resolves who actually holds the
   task's role on a given study, by chaining task.role → study.roleAssignments →
   team.roles[*].holders. Falls back to direct user-id lookup for back-compat
   with the existing seed data where task.role stores a user id.

   Returns a user object or null. */
const resolveTaskAssignee = (task, study, teams) => {
  if (!task || !task.role) return null;
  const direct = USERS.find(u => u.id === task.role);
  if (direct) return direct; /* legacy: task.role IS a user id */
  /* Otherwise treat task.role as a role-slot id, look up the holder via study.roleAssignments. */
  const holderId = (study?.roleAssignments || {})[task.role];
  if (holderId) {
    const u = USERS.find(u => u.id === holderId);
    if (u) return u;
  }
  /* Fall back: scan all teams for a role with this id and use its first holder. */
  for (const team of (teams || [])) {
    const role = (team.roles || []).find(r => r.id === task.role);
    if (role) {
      const fallbackId = (role.holders || [])[0];
      if (fallbackId) return USERS.find(u => u.id === fallbackId) || null;
    }
  }
  return null;
};

/* SP6-005 — time-tracking derived metrics. Computes standard analytics fields
   on demand: days elapsed since each milestone, time-to-current-stage, etc.
   Output feeds Analytics dashboards and per-study reporting. */
const computeStudyMetrics = (study) => {
  if (!study) return {};
  const today0 = new Date(); today0.setHours(0,0,0,0);
  const dayDiff = (iso) => iso ? Math.floor((today0 - new Date(iso)) / 86400000) : null;
  return {
    daysSinceIntake:        dayDiff(study.intakeDate),
    daysSinceCommit:        dayDiff(study.committedAt),
    daysSinceActivation:    dayDiff(study.details?.activationDate || study.siv?.completedDate),
    daysToCommit:           study.intakeDate && study.committedAt ? Math.floor((new Date(study.committedAt) - new Date(study.intakeDate)) / 86400000) : null,
    daysToActivation:       study.committedAt && study.details?.activationDate ? Math.floor((new Date(study.details.activationDate) - new Date(study.committedAt)) / 86400000) : null,
    daysSinceLastComm:      dayDiff(((study.communications || [])[0] || {}).date),
    openTaskCount:          (study.tasks || []).filter(t => t.status !== "completed").length,
    overdueTaskCount:       (study.tasks || []).filter(t => t.status !== "completed" && t.due && new Date(t.due) < today0).length,
    openEscalationCount:    (study.escalations || []).filter(e => !e.resolvedDate).length,
  };
};

/* SP2-007 — per-phase Project Managers. Each pipeline stage has a default-
   owning team (stage.ownerTeamId, exposed via the live STAGE_TO_TEAM binding
   built near DEFAULT_PIPELINE_STAGES); the team's manager-hierarchy role-holder
   is the de-facto PM for studies in that stage. */

/* Returns the manager-role holder for a given stage, or null. */
const getStagePM = (stageKey, teams) => {
  const tid = STAGE_TO_TEAM[stageKey];
  if (!tid) return null;
  const team = (teams || []).find(t => t.id === tid);
  if (!team) return null;
  /* Prefer manager-hierarchy role; fall back to first role with any holder. */
  const managerRole = (team.roles || []).find(r => r.hierarchyKey === "manager") || (team.roles || []).find(r => (r.holders || []).length > 0);
  const holderId = (managerRole?.holders || [])[0];
  if (!holderId) return null;
  const user = USERS.find(u => u.id === holderId);
  return user ? { user, team, role: managerRole } : null;
};

/* SP1-008 — activated-study status. PLACEHOLDER enum pending Chad's confirmation;
   labels are the four most common active-study states a clinical research site tracks.
   When stage === "activation", the active-study header surfaces this as an editable
   dropdown so the director can move a live study through its post-activation phases. */
const ACTIVATED_STATUSES = {
  enrollment:        { label:"Enrollment",          color:"#059669", bg:"#d1fae5", desc:"Actively enrolling subjects." },
  closed_to_enroll:  { label:"Closed to enrollment",color:"#4F46E5", bg:"#EEF2FF", desc:"Enrollment closed; subjects in follow-up or treatment." },
  follow_up:         { label:"In follow-up",        color:"#7C3AED", bg:"#F5F3FF", desc:"All subjects past treatment; in long-term follow-up." },
  closeout:          { label:"Closeout",            color:"#b45309", bg:"#fef3c7", desc:"Study closing — final reports, document archival, sponsor sign-off." },
};
const ACTIVATED_STATUS_KEYS = Object.keys(ACTIVATED_STATUSES);

/* SP0-004 — auto-generated, org-configurable Project ID.
   Format: <prefix>-<3-digit zero-padded sequence>. Prefix is set in the
   wizard Stage 1 (settings.org.projectIdPrefix, defaults to "STU"). Sequence
   advances on every new study commit. Seeded studies have hardcoded IDs;
   new studies get one via nextProjectId(). */
const formatProjectId = (prefix, n) => `${prefix || "STU"}-${String(n || 0).padStart(3, "0")}`;

/* Compute the next available Project ID by scanning existing studies for
   matching-prefix IDs and taking max + 1. */
const nextProjectId = (studies, prefix) => {
  const p = prefix || "STU";
  const re = new RegExp(`^${p}-(\\d+)$`);
  const max = (studies || []).reduce((m, s) => {
    const match = s.projectId && re.exec(s.projectId);
    return match ? Math.max(m, parseInt(match[1], 10)) : m;
  }, 0);
  return formatProjectId(p, max + 1);
};

/* Lazy lookup: if the study has a stored projectId, use it; otherwise compute
   a deterministic fallback from its position in the studies list so the demo
   has IDs even before any explicit assignment. */
const projectIdFor = (study, studies, prefix) => {
  if (!study) return "";
  if (study.projectId) return study.projectId;
  const idx = (studies || []).findIndex(s => s.id === study.id);
  return formatProjectId(prefix, (idx >= 0 ? idx : 0) + 1);
};

/* SP0-003 — priority flag. Every study has one. Defaults to "standard".
   Director can flag Priority or Urgent for visibility. Used by Today's
   "what needs me first" sort and rendered as a small chip everywhere. */
const PRIORITY_META = {
  standard: { label:"Standard", color:"#64748b", bg:"#f1f5f9", iconKey:null,    rank:0 },
  priority: { label:"Priority", color:"#b45309", bg:"#fef3c7", iconKey:"flag",  rank:1 },
  urgent:   { label:"Urgent",   color:"#dc2626", bg:"#fee2e2", iconKey:"alert", rank:2 },
};
const PRIORITY_KEYS = ["standard","priority","urgent"];

/* Compact priority chip. Standard is muted (a thin outline) so it doesn't
   compete with Priority/Urgent visually. Hidden entirely in `hideStandard` mode. */
const PriorityChip = ({ priority, hideStandard=false, size="sm" }) => {
  const p = priority || "standard";
  if (hideStandard && p === "standard") return null;
  const meta = PRIORITY_META[p] || PRIORITY_META.standard;
  return (
    <span title={`Priority: ${meta.label}`}
      style={{
        display:"inline-flex", alignItems:"center", gap:4,
        padding: size === "sm" ? "1px 7px" : "2px 9px",
        borderRadius: T.radius.pill,
        background: meta.bg, color: meta.color,
        border: p === "standard" ? `1px solid ${T.color.borderSubtle}` : "none",
        fontSize: 10, fontWeight:T.weight.bold,
        letterSpacing:"0.04em", textTransform:"uppercase",
        whiteSpace:"nowrap",
      }}>
      {meta.iconKey && <Icon name={meta.iconKey} size={8} color={meta.color} />}
      {meta.label}
    </span>
  );
};

/* SP0-002 — stage countdown chip. Renders e.g. "-152d" in red for overdue,
   "12d left" in green for on-track. Tooltip shows the target + elapsed. */
const StageCountdownChip = ({ study, stageKey, size="sm" }) => {
  const effective = stageKey || study?.stage;
  if (!STAGE_HAS_COUNTDOWN(effective)) return null;
  const cd = computeStageCountdown(study, effective);
  if (!cd) return null;
  const palette = {
    overdue:   { color:"#dc2626", bg:"#fee2e2" },
    late:      { color:"#b45309", bg:"#fef3c7" },
    "due-soon":{ color:"#b45309", bg:"#fef3c7" },
    "on-track":{ color:"#059669", bg:"#d1fae5" },
  }[cd.status];
  return (
    <span title={`Target: ${cd.target}d from commit · elapsed: ${cd.elapsed}d`}
      style={{
        display:"inline-flex", alignItems:"center", gap:4,
        padding: size === "sm" ? "1px 7px" : "2px 9px",
        borderRadius:T.radius.pill,
        background: palette.bg, color: palette.color,
        fontSize: 10, fontWeight:T.weight.bold,
        letterSpacing:"0.03em", whiteSpace:"nowrap",
        fontFamily:T.font.mono,
        fontVariantNumeric:"tabular-nums",
      }}>
      {stageCountdownLabel(cd)}
    </span>
  );
};

/* SP0-001 — small project-health badge. Renders the R/Y/G dot with optional
   tooltip showing the reason. Compact mode hides the label and uses a dot only. */
const HealthPill = ({ study, compact=false, showReason=false }) => {
  const h = computeProjectHealth(study);
  const meta = PROJECT_HEALTH_META[h.level];
  if (compact) {
    return (
      <span title={`${meta.label} — ${h.reason}`}
        style={{ display:"inline-block", width:10, height:10, borderRadius:"50%", background:meta.color, flexShrink:0 }} />
    );
  }
  return (
    <span title={h.reason}
      style={{
        display:"inline-flex", alignItems:"center", gap:5,
        padding:"2px 9px", borderRadius:T.radius.pill,
        background: meta.bg, color: meta.color,
        fontSize: T.font.xs, fontWeight:T.weight.bold,
        letterSpacing:"0.04em", textTransform:"uppercase",
        lineHeight:1.4, whiteSpace:"nowrap",
      }}>
      <span style={{ width:6, height:6, borderRadius:"50%", background: meta.color, flexShrink:0 }} />
      {meta.label}{showReason && h.daysOverdue ? ` · ${h.daysOverdue}d` : ""}
    </span>
  );
};

