    phase2:       { label:"Phase 2",    bg:T.color.surfaceAlt, color:T.color.textSecondary },
    phase3:       { label:"Phase 3",    bg:"transparent", color:T.color.textFaint, border:`1px dashed ${T.color.border}` },
    progress:     { label:"In Progress",bg:T.color.brandBg, color:T.color.brand },
    pending:      { label:"Pending",    bg:T.color.warningBg, color:T.color.warning },
    submitted:    { label:"Submitted",  bg:T.color.primaryBg, color:T.color.primary },
    under_review: { label:"Under Review",bg:T.color.warningBg, color:T.color.warning },
    qc_pending:   { label:"QC pending", bg:T.color.brandBg, color:T.color.brand },
    qc_failed:    { label:"QC failed",  bg:T.color.dangerBg, color:T.color.danger },
    unfiled:      { label:"Unfiled",    bg:T.color.warningBg, color:T.color.warning },
    removed:      { label:"Removed",    bg:T.color.dangerBg, color:T.color.danger },
    approved:     { label:"Approved",   bg:T.color.successBg, color:T.color.success },
    current:      { label:"Current",    bg:T.color.successBg, color:T.color.success },
    rejected:     { label:"Rejected",   bg:T.color.dangerBg, color:T.color.danger },
    archived:     { label:"Archived",   bg:T.color.surfaceAlt, color:T.color.textFaint },
    not_started:  { label:"Not Started",bg:T.color.surfaceAlt, color:T.color.textFaint },
    negotiating:  { label:"Negotiating",bg:T.color.brandBg, color:T.color.brand },
    executed:     { label:"Executed",   bg:T.color.successBg, color:T.color.success },
    in_progress:  { label:"In Progress",bg:T.color.brandBg, color:T.color.brand },
    completed:    { label:"Completed",  bg:T.color.successBg, color:T.color.success },
    todo:         { label:"To Do",      bg:T.color.surfaceAlt, color:T.color.textSecondary },
    reached_out:  { label:"Reached Out",bg:T.color.primaryBg, color:T.color.primary },
    interested:   { label:"Interested", bg:T.color.warningBg, color:T.color.warning },
    committed:    { label:"Committed",  bg:T.color.successBg, color:T.color.success },
    high:         { label:"High",       bg:T.color.dangerBg, color:T.color.danger },
    medium:       { label:"Medium",     bg:T.color.warningBg, color:T.color.warning },
    low:          { label:"Low",        bg:T.color.primaryBg, color:T.color.primary },
